#include <bits/stdc++.h>
using namespace std;

map<string, string> fa;

string find(string x)
{
    return fa[x] == x ? x : fa[x] = find(fa[x]);
}

int main()
{
	char ch;
	string s, f;
    while(cin >> ch)
    {
    	if(ch == '$') break;
    	cin >> s;
    	if(ch == '#') 
    	{
    		f = s;
    		if(fa[s] == "") fa[s] = s;
    	}
    	else if(ch == '+')
    		fa[s] = f;
    	else 
    		cout << s << ' ' << find(s) << endl;
    }
    return 0;
}
